<template>
    <section>

        <loader :is-visible="isLoading"></loader>

        <tg-list :IsShowAction="false" ref="tgList" :showCheckBox="false" ModuleName="Billing"
            SubModuleCode="Exceptions" IdentityColumn="EXCEPTIONID" HeaderText="Integration Exception"
            :ListData="ExceptionsData" :listType="ListView" :HeaderData="Headers"
            :NorecordfoundText="$t('NoRecordfound')" :TotalRecords="TotalRecords" :SearchFields="leftsearchSchema"
            :RenderRowActionMethod="renderActions" :ListDataCallBackFunction="GetExceptionsData" :LegendArray="[]"
            :SortExp="sortExp" :SortBy="sortBy" :HeaderButtons="listheaderbuttons" :CurrentPageNumber="pageNum"
            :widgets="[]" v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:ActionButtonClick="actionButtonClick"
            v-on:SortdataButtonClick="sortdata">


        </tg-list>

    </section>
</template>

<script>

import DataService from "../../services/DataService";
import Schema from "./ExceptionSchema";

export default {
    name: "Exceptions",
    components: {},
    data() {
        return {
            isLoading: false,
            ListView: ['List'],
            listheaderbuttons: [],
            ExceptionsData: [],
            TotalRecords: 0,
            pageSize: 10,
            pageNum: 1,
            sortBy: '',
            searchCondition: '',
            TotalPages: 0,
            sortExp: '',
            UserType: 'CA',
            Headers: [
                {
                    COLUMN_NAME: "TITLE",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: "TITLE",
                    DISPLAY_ORDER: 1,
                }, {
                    COLUMN_NAME: "TYPE",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: "TYPE",
                    DISPLAY_ORDER: 2,
                }, {
                    COLUMN_NAME: "EXCEPTION",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: "EXCEPTION",
                    DISPLAY_ORDER: 3,
                },
                {
                    COLUMN_NAME: "CREATED_AT",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: "Date",
                    DISPLAY_ORDER: 4,
                },
                {
                    COLUMN_NAME: "MODE",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: "Integration",
                    DISPLAY_ORDER: 5,
                }

            ],
            leftsearchSchema: Schema.leftsearchSchema,
            Search_By: null,
            Integration: null,
            DateFrom: null,
            DateTo: null
        }
    },

    created: async function () {
        //debugger
        const vm = this;
        vm.isLoading = true;

        try {
            await Promise.all([
                vm.GetExceptionsData(),
                Schema.bindleftCommonSearchdropdown(vm, 'SEARCH_BY'),
                Schema.bindleftCommonSearchdropdown(vm, 'INTEGRATION')
            ]);
        } catch (err) {
            console.error(err);
        } finally {
            vm.isLoading = false; // ✅ hides only after page is fully ready
        }
    },
    methods: {

        GetExceptionsData: async function () {
            debugger
            var vm = this;

            var Url = `UserType=${vm.UserType}&search=&searchBy=${vm.Search_By}&pageSize=${vm.pageSize}&pageNum=${vm.pageNum}&sortBy=${vm.sortBy}&sortExp=${vm.sortExp}&fromdate=${vm.DateFrom}&todate=${vm.DateTo}&intgId=${vm.Integration}&errorBatchId= `;
            await DataService.GetExceptionsData(Url).then((response) => {
                if (response.data) {

                    vm.ExceptionsData = response.data.result;

                    // vm.ExceptionsData.forEach(item => {
                    //     item.CREATED_AT = item.CREATED_AT.split('T')[0];
                    //     item.CREATED_AT = new Date(item.CREATED_AT).toLocaleDateString('en-US');
                    // });

                    vm.ExceptionsData.forEach(item => {
                        const d = new Date(item.CREATED_AT);
                        const mm = String(d.getMonth() + 1).padStart(2, '0');
                        const dd = String(d.getDate()).padStart(2, '0');
                        const yyyy = d.getFullYear();

                        item.CREATED_AT = `${mm}-${dd}-${yyyy}`;
                    });

                    vm.TotalRecords = vm.ExceptionsData[0].TOTALRECORDS;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.pageNum;
                }


            });
        },
        renderActions: function (row) {

            var self = this;
            let rtnActionArray = [];
            return rtnActionArray;
        },
        actionButtonClick: function (callbackfunction, item) {

            switch (callbackfunction) {

            }
        },
        commonHeaderButtonClick: function (event) {

            switch (event.callbackfunction) {

            }
        },
        pagerMethod: function (value) {

            this.pageSize = value.pageSize;
            this.pageNum = value.pageNum;
            this.GetExceptionsData();
        },
        leftCommonSearch: async function (value) {
            debugger
            this.pageNum = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                this.searchCondition = value.searchCondition;

                let str = value.searchConditionJson;

                const params = new URLSearchParams(str);

                this.Search_By = params.get('SEARCH_BY') || '';
                this.Integration = params.get('INTEGRATIONS') || '';
                this.DateFrom = params.get('DATE_FROM') || '';
                this.DateTo = params.get('DATE_TO') || '';
            }
            else {
                this.searchCondition = "";
                this.Search_By = '';
                this.Integration = '';
                this.DateFrom = '';
                this.DateTo = '';

            }

            this.GetExceptionsData();
        },
        sortdata: function (s) {

            var SortDir = "sort tb_headerSortDown";
            this.sortBy = s;
            if (s === this.sortBy) {
                if (this.sortExp == "") {
                    this.sortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
                else if (this.sortExp == "ASC") {
                    this.sortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                }
                else {
                    this.sortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            this.GetExceptionsData();
            $("#" + s + '  span:first-child').attr("class", SortDir);
        },

    }
}
</script>

